/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwwZoopPagamentos-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&FilCod.IsEmpty() AND &ZoopTip.IsEmpty() AND &ZoopJaspiSts.IsEmpty()) &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = &FilCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &ZoopTip.ToString().Trim() = "B" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "BOLETO"
Case &ZoopTip.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "CARTAO_CREDITO"
Case &ZoopTip.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "CARTAO_DEBITO"
Case &ZoopTip.ToString().Trim() = "E" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "COMISSÃO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = '' do Case Case &ZoopJaspiSts.ToString().Trim() = "P" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "PENDENTE"
Case &ZoopJaspiSts.ToString().Trim() = "V" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "VINCULADO"
Case &ZoopJaspiSts.ToString().Trim() = "L" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "LIQUIDADO"
Case &ZoopJaspiSts.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "CANCELADO"
EndCase EndIf If not (&ZoopDtaUpd.IsEmpty() AND &ZoopDtaUpd_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Atualizado") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &ZoopDtaUpd WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, " - ") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &ZoopDtaUpd_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'ZOOPCARDID' &ZoopCardId1.FromString(&GridStateDynamicFilter.Value) If not &ZoopCardId1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Autorização" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopCardId1) EndIf Case &DynamicFiltersSelector1 = !'ZOOPBOLID' &ZoopBolId1.FromString(&GridStateDynamicFilter.Value) If not &ZoopBolId1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Boleto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopBolId1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'ZOOPCARDID' &ZoopCardId2.FromString(&GridStateDynamicFilter.Value) If not &ZoopCardId2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Autorização" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopCardId2) EndIf Case &DynamicFiltersSelector2 = !'ZOOPBOLID' &ZoopBolId2.FromString(&GridStateDynamicFilter.Value) If not &ZoopBolId2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Boleto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopBolId2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'ZOOPCARDID' &ZoopCardId3.FromString(&GridStateDynamicFilter.Value) If not &ZoopCardId3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Autorização" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopCardId3) EndIf Case &DynamicFiltersSelector3 = !'ZOOPBOLID' &ZoopBolId3.FromString(&GridStateDynamicFilter.Value) If not &ZoopBolId3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Boleto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&ZoopBolId3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Id" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Sts.JASPI" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "TIPO" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Taxas" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Data" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Cli.Cod" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Cli.Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Cartao" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "NSU" &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "Boleto" &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Text = "Atualizado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Text = "Bandeira"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order ZoopJaspiSts when &OrderedBy = 1 AND &OrderedDsc = False order (ZoopJaspiSts) when &OrderedBy = 1 AND &OrderedDsc = True order ZoopId when &OrderedBy = 2 AND &OrderedDsc = False order (ZoopId) when &OrderedBy = 2 AND &OrderedDsc = True order ZoopTip when &OrderedBy = 3 AND &OrderedDsc = False order (ZoopTip) when &OrderedBy = 3 AND &OrderedDsc = True order ZoopVlr when &OrderedBy = 4 AND &OrderedDsc = False order (ZoopVlr) when &OrderedBy = 4 AND &OrderedDsc = True order ZoopTax when &OrderedBy = 5 AND &OrderedDsc = False order (ZoopTax) when &OrderedBy = 5 AND &OrderedDsc = True order ZoopDta when &OrderedBy = 6 AND &OrderedDsc = False order (ZoopDta) when &OrderedBy = 6 AND &OrderedDsc = True order ZoopCodCli when &OrderedBy = 7 AND &OrderedDsc = False order (ZoopCodCli) when &OrderedBy = 7 AND &OrderedDsc = True order ZoopNomCli when &OrderedBy = 8 AND &OrderedDsc = False order (ZoopNomCli) when &OrderedBy = 8 AND &OrderedDsc = True order ZoopCardId when &OrderedBy = 9 AND &OrderedDsc = False order (ZoopCardId) when &OrderedBy = 9 AND &OrderedDsc = True order ZoopCardNSU when &OrderedBy = 10 AND &OrderedDsc = False order (ZoopCardNSU) when &OrderedBy = 10 AND &OrderedDsc = True order ZoopBolId when &OrderedBy = 11 AND &OrderedDsc = False order (ZoopBolId) when &OrderedBy = 11 AND &OrderedDsc = True order ZoopDtaUpd when &OrderedBy = 12 AND &OrderedDsc = False order (ZoopDtaUpd) when &OrderedBy = 12 AND &OrderedDsc = True order ZoopCarBan when &OrderedBy = 13 AND &OrderedDsc = False order (ZoopCarBan) when &OrderedBy = 13 AND &OrderedDsc = True
using DSwwZoopPagamentos(&FilCod, &ZoopTip, &ZoopJaspiSts, &DynamicFiltersSelector1, &ZoopCardId1, &ZoopBolId1 , &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &ZoopCardId2, &ZoopBolId2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3 , &ZoopCardId3, &ZoopBolId3, &ZoopDtaUpd, &ZoopDtaUpd_To)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(ZoopId) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case ZoopJaspiSts.ToString().Trim() = "P" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "PENDENTE"
Case ZoopJaspiSts.ToString().Trim() = "V" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "VINCULADO"
Case ZoopJaspiSts.ToString().Trim() = "L" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "LIQUIDADO"
Case ZoopJaspiSts.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "CANCELADO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = '' do Case Case ZoopTip.ToString().Trim() = "B" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "BOLETO"
Case ZoopTip.ToString().Trim() = "C" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "CARTAO_CREDITO"
Case ZoopTip.ToString().Trim() = "D" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "CARTAO_DEBITO"
Case ZoopTip.ToString().Trim() = "E" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "COMISSÃO"
EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = ZoopVlr &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = ZoopTax &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = ZoopDta &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(ZoopCodCli) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = WWP_Export_SecureText(ZoopNomCli) &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(ZoopCardId) &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = WWP_Export_SecureText(ZoopCardNSU) &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = WWP_Export_SecureText(ZoopBolId) &ExcelDocument.Cells(&CellRow, &FirstColumn + 11).Date = ZoopDtaUpd &ExcelDocument.Cells(&CellRow, &FirstColumn + 12).Text = WWP_Export_SecureText(ZoopCarBan)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwZoopPagamentosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwZoopPagamentosGridState")) Else &GridState.FromXml(&Session.Get(!"wwZoopPagamentosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"ZOOPTIP" &ZoopTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"ZOOPJASPISTS" &ZoopJaspiSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"ZOOPDTAUPD" &ZoopDtaUpd.FromString(&GridStateFilterValue.Value) &ZoopDtaUpd_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

